def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 7:
            for a in range(7, 0, -1):
                for b in range(1, a + 5):
                    component = ((ratio - a) ** 6) / ((a + b) * 1.1 + 1)
                    trig = np.sin(ratio * b / (a + 2)) + np.cos(ratio * a / (b + 1))
                    priority += component * trig ** 2
            priority += (np.exp(ratio - 7) * np.cos(ratio * 1.3)) ** 1.7
            if bin_cap < item * 0.5:
                priority += np.log1p(item * bin_cap) * 8
        elif 4 < ratio <= 7:
            for p in range(1, int(np.ceil(ratio)) + 5):
                for q in range(1, p + 4):
                    term = ((ratio - p) ** 4) * np.cos(ratio * p * 1.2) / (q + 1)
                    priority += np.tanh(term) * 1.4
            priority += np.log(ratio) * 12 - np.tanh(ratio - 4.5) * 3.5
            if bin_cap > item * 3:
                priority -= np.sqrt(bin_cap - item * 3) * 2
        elif 2 <= ratio <= 4:
            temp_sum = 0
            for r in range(1, 15):
                val = ((ratio - 2) ** r) / (r * 2.0) * np.sin(r * ratio * 1.1)
                temp_sum += val
            priority = temp_sum * np.cos(9 * ratio) - np.log(ratio) * 8 + np.tanh(5 * (4.5 - ratio)) * 2.2
            for s in range(1, 6):
                priority += np.sin(s * item * ratio) * ((ratio - 1.9) ** (s + 1)) / (s + 0.5)
        elif 1 <= ratio < 2:
            summ = 0
            for n in range(1, 20):
                summ += ((2 - ratio) ** n) / (n**3 + 1) * np.cos(n * ratio * 1.3)
            if bin_cap < item * 0.9:
                penalty = np.sqrt(item / (bin_cap + 0.1)) * 5
            else:
                penalty = np.sin(25 * ratio) * 3
            priority = summ + penalty + np.exp(-2.0 / (ratio + 0.1))
            for m in range(1, 7):
                priority += np.cos(m * ratio * i * 1.2) * ((ratio - 1) ** m) / (m * 1.5)
        elif 0.5 <= ratio < 1:
            summ = 0
            for n in range(1, 25):
                summ += ((1 - ratio) ** n) / (n * 3) * np.sin(n * item * 1.7)
            priority = summ
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 4) * 1.6
            else:
                priority /= (np.sqrt(bin_cap + 2) + 1.5)
            for j in range(1, 8):
                priority += ((1 - ratio) ** j) * np.cos(j * item * 1.5) * 0.9
        elif 0.15 <= ratio < 0.5:
            ssum = 0
            for k in range(1, 18):
                ssum += ((0.5 - ratio) ** k) / (k * 4) * np.cos(k * ratio * 2.3)
            priority = ssum + 1 / (bin_cap + 4)
            if int(item * 1.8) % 5 == 0:
                priority *= 3.5
            else:
                priority /= 3.7
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 1.5) * 4
            for m in range(1, 10):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.sin(item * m * 1.4)
        else:
            tsum = 0
            for t in range(1, 15):
                tsum += ((0.15 - ratio) ** t) / (t * 6) * np.cos(t * item * 1.0)
            priority = tsum + 3 / (bin_cap + 5)
            if int(item * 0.9) % 6 == 0:
                priority *= 4
            else:
                priority /= 4.2
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for u in range(1, 12):
                priority += ((0.15 - ratio) ** u) / (u * 8) * np.sin(item * u * 0.9)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 3 * bin_cap) * 6.5
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 6):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.1) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.1) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.8
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.8
        if i % 2 == 0 and bin_cap > item:
            priority *= 1.1
        elif i % 2 == 1 and bin_cap < item:
            priority /= 1.1
        priorities[i] = priority
    return priorities
